.span-latency {
  font-family: var(--font-mono);
  font-size: 11px;
  font-weight: 600;
}

.event-row {
  display: flex;
  align-items: center;
  gap: 8px;
  padding: 4px 0;
  font-size: 11px;
}

.event-dot {
  width: 6px;
  height: 6px;
  border-radius: 50%;
  flex-shrink: 0;
}

.event-msg {
  flex: 1;
  color: var(--text-primary);
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}

.event-ts {
  font-family: var(--font-mono);
  color: var(--text-dim);
  font-size: 10px;
}

/* --- Graph View (placeholder) --- */
.graph-view {
  flex: 1;
  display: flex;
  align-items: center;
  justify-content: center;
}

.graph-placeholder {
  text-align: center;
  color: var(--text-muted);
}

.placeholder-icon {
  font-size: 48px;
  margin-bottom: 16px;
}

.graph-placeholder h3 {
  font-size: 18px;
  color: var(--text-bright);
  margin-bottom: 8px;
}

.placeholder-text {
  font-size: 13px;
}

.placeholder-text code {
  font-family: var(--font-mono);
  background: var(--bg-input);
  padding: 2px 6px;
  border-radius: 4px;
  font-size: 12px;
}

/* --- Config Panel --- */
.config-panel {
  background: var(--bg-card);
  border: 1px solid var(--border);
  border-radius: var(--radius-lg);
  padding: 20px;
}

.config-title {
  font-size: 11px;
  text-transform: uppercase;
  letter-spacing: 0.07em;
  font-weight: 700;
  color: var(--text-muted);
  margin-bottom: 16px;
}

.config-row {
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 10px 0;
  border-bottom: 1px solid var(--border-subtle);
}

.config-key {
  font-size: 12px;
  color: var(--text-muted);
}
